// RUN: objc3c -x objective-c++ -fobjc-version=3 -fsyntax-only %s
typedef enum objc_async_completion_status {
    OBJC_ASYNC_COMPLETION_SUCCESS = 0,
    OBJC_ASYNC_COMPLETION_ERROR = 1,
    OBJC_ASYNC_COMPLETION_CANCELLED = 2
} objc_async_completion_status_t;

typedef void (*INTCXX01Completion)(
    void * _Nullable context,
    objc_async_completion_status_t status,
    id _Nullable result,
    id<Error> _Nullable error);

id intcxx01_fetch(int token) async throws;
void intcxx01_fetch_async_c(int token,
                            void * _Nullable context,
                            INTCXX01Completion _Nonnull completion);

id intcxx01_retain(id _Nullable value);
void intcxx01_release(id _Nullable value);

struct INTCXX01RetainSlot {
    id _Nullable saved;
    INTCXX01RetainSlot() : saved(nil) {}
    ~INTCXX01RetainSlot() {
        if (saved != nil) {
            intcxx01_release(saved);
        }
    }
    void store(id _Nullable value) {
        if (value != nil) {
            saved = intcxx01_retain(value);
        }
    }
};

void intcxx01_callback(void * _Nullable context,
                       objc_async_completion_status_t status,
                       id _Nullable result,
                       id<Error> _Nullable error) {
    INTCXX01RetainSlot *slot = (INTCXX01RetainSlot *)context;
    if (status == OBJC_ASYNC_COMPLETION_SUCCESS) {
        slot->store(result);
    }
    if (error != nil) {
        slot->store((id)error);
    }
}
